('COMMERCIAL(E)', '', 'manual_extraction_5', '23/03/2026', 'BAC+2', 'Stage Commercial dans un cabinet de formation. Missions : prospecter de nouveaux clients, présenter les services, répondre aux demandes, contribuer à la préparation de devis, participer à des réunions de suivi, aider à l''organisation d''événements de formation. Profil : étudiant(e) en commerce, marketing ou communication, intérêt pour la formation, bonnes compétences en communication et en relation client, capacité à travailler en équipe, maîtrise des outils bureautiques (Word, Excel, PowerPoint).', '', '', '', 'recrutementysed@gmail.com', true, 'Cocody nouveau CH angre', ARRAY['Stage', 'Commerce', 'Formation', 'Prospection'], false, '', '{"title": "COMMERCIAL(E)", "company_name": null, "summary": "Stage Commercial dans un cabinet de formation. Missions : prospecter de nouveaux clients, pr\u00e9senter les services, r\u00e9pondre aux demandes, contribuer \u00e0 la pr\u00e9paration de devis, participer \u00e0 des r\u00e9unions de suivi, aider \u00e0 l''organisation d''\u00e9v\u00e9nements de formation. Profil : \u00e9tudiant(e) en commerce, marketing ou communication, int\u00e9r\u00eat pour la formation, bonnes comp\u00e9tences en communication et en relation client, capacit\u00e9 \u00e0 travailler en \u00e9quipe, ma\u00eetrise des outils bureautiques (Word, Excel, PowerPoint).", "contact": null, "lettre_motivation": null, "objet": null, "urls": null, "email": "recrutementysed@gmail.com", "deadline": "23/03/2026", "niveau": "BAC+2", "lieu": "Cocody nouveau CH angre", "tags": ["Stage", "Commerce", "Formation", "Prospection"], "salary_range": null}'),
('ADMINISTRATIF(VE) BILINGUE – GESTION VÉHICULES À L’INTERNATIONAL', '', 'manual_extraction_6', '23/03/2026', 'BAC+5', 'Recrutement d''un(e) Administratif(ve) Bilingue. Missions : gérer l''ensemble des dossiers administratifs des véhicules à l''étranger, mettre à jour et organiser les dossiers administratifs, rédiger et traiter courriers, emails et documents en français et en anglais, assurer le suivi complet des dossiers, classer, archiver, coordonner avec les interlocuteurs, veiller au respect des procédures et délais. Profil : formation en administration, gestion ou secrétariat, expérience significative, bilingue français/anglais (écrit et oral) indispensable, maîtrise des outils bureautiques, organisé(e), rigoureux(se), discret(e), fiable, autonome, polyvalent(e), capable de gérer les priorités de manière proactive.', '', '', '33753430708', '', true, 'ABIDJAN ANGRE NOUVEAU CHU', ARRAY['Administratif', 'Bilingue', 'Gestion de flotte', 'Anglais'], false, '', '{"title": "ADMINISTRATIF(VE) BILINGUE \u2013 GESTION V\u00c9HICULES \u00c0 L\u2019INTERNATIONAL", "company_name": null, "summary": "Recrutement d''un(e) Administratif(ve) Bilingue. Missions : g\u00e9rer l''ensemble des dossiers administratifs des v\u00e9hicules \u00e0 l''\u00e9tranger, mettre \u00e0 jour et organiser les dossiers administratifs, r\u00e9diger et traiter courriers, emails et documents en fran\u00e7ais et en anglais, assurer le suivi complet des dossiers, classer, archiver, coordonner avec les interlocuteurs, veiller au respect des proc\u00e9dures et d\u00e9lais. Profil : formation en administration, gestion ou secr\u00e9tariat, exp\u00e9rience significative, bilingue fran\u00e7ais/anglais (\u00e9crit et oral) indispensable, ma\u00eetrise des outils bureautiques, organis\u00e9(e), rigoureux(se), discret(e), fiable, autonome, polyvalent(e), capable de g\u00e9rer les priorit\u00e9s de mani\u00e8re proactive.", "contact": "+33 7 53 43 07 08 (WhatsApp)", "lettre_motivation": null, "objet": null, "urls": null, "email": null, "deadline": "23/03/2026", "niveau": "BAC+5", "lieu": "ABIDJAN ANGRE NOUVEAU CHU", "tags": ["Administratif", "Bilingue", "Gestion de flotte", "Anglais"], "salary_range": null}'),
('AIDE SOIGNANT', 'ICM', 'manual_extraction_7', '23/03/2026', 'BEPC', 'ICM offre une formation professionnelle pour aide soignant (3 mois théorie + 3 mois stage garanti). Certificats reconnus par les gouvernements Ivoirien et Canadien. Possibilité de poursuivre au Canada après expérience. Profil : niveau BEPC, vivre en Côte d''Ivoire.', '', '', '', 'canadaicm@gmail.com', true, 'Côte d''Ivoire', ARRAY['Formation', 'Aide soignant', 'Santé'], true, 'OUI (lettre d''intérêt pour la formation)', '{"title": "AIDE SOIGNANT", "company_name": "ICM", "summary": "ICM offre une formation professionnelle pour aide soignant (3 mois th\u00e9orie + 3 mois stage garanti). Certificats reconnus par les gouvernements Ivoirien et Canadien. Possibilit\u00e9 de poursuivre au Canada apr\u00e8s exp\u00e9rience. Profil : niveau BEPC, vivre en C\u00f4te d''Ivoire.", "contact": null, "lettre_motivation": "OUI (lettre d''int\u00e9r\u00eat pour la formation)", "objet": null, "urls": null, "email": "canadaicm@gmail.com", "deadline": "23/03/2026", "niveau": "BEPC", "lieu": "C\u00f4te d''Ivoire", "tags": ["Formation", "Aide soignant", "Sant\u00e9"], "salary_range": null}'),
