('COMMERCIAL EXPERIMENTÉ', '', 'manual_extraction_13', '23/04/2026', 'BAC+2, BAC', 'Entreprise de cosmétiques recherche des commerciaux expérimentés avec un portefeuille clients important. Missions : développer le portefeuille clients, promouvoir les produits, contribuer à la croissance. Profil : expérience préalable dans la vente de produits cosmétiques, dynamique, excellent sens du relationnel, forte capacité de persuasion, passionné de l''industrie des cosmétiques, bon portefeuille-client local et international, capacité à s''organiser et à travailler en vue d''atteindre ses objectifs.', 'COMMERCIAL', '', '', 'commercial@dharma-cosmetics.com', true, 'Côte d''Ivoire', ARRAY['Vente', 'Cosmétiques', 'Portefeuille client', 'B2B'], true, 'OUI', '{"title": "COMMERCIAL EXPERIMENT\u00c9", "company_name": null, "summary": "Entreprise de cosm\u00e9tiques recherche des commerciaux exp\u00e9riment\u00e9s avec un portefeuille clients important. Missions : d\u00e9velopper le portefeuille clients, promouvoir les produits, contribuer \u00e0 la croissance. Profil : exp\u00e9rience pr\u00e9alable dans la vente de produits cosm\u00e9tiques, dynamique, excellent sens du relationnel, forte capacit\u00e9 de persuasion, passionn\u00e9 de l''industrie des cosm\u00e9tiques, bon portefeuille-client local et international, capacit\u00e9 \u00e0 s''organiser et \u00e0 travailler en vue d''atteindre ses objectifs.", "contact": null, "lettre_motivation": "OUI", "objet": "COMMERCIAL", "urls": null, "email": "commercial@dharma-cosmetics.com", "deadline": "23/04/2026", "niveau": "BAC+2, BAC", "lieu": "C\u00f4te d''Ivoire", "tags": ["Vente", "Cosm\u00e9tiques", "Portefeuille client", "B2B"], "salary_range": null}'),
