('RESPONSABLES RESSOURCES HUMAINES BILINGUE', 'UMO CI (pour client, distribution de solutions solaires)', 'manual_extraction_160', '30/03/2026', 'BAC+4', 'UMO CI recrute un(e) Responsable RH bilingue (Français/Anglais) pour une entreprise de distribution de solutions solaires photovoltaïques. Missions : définition et mise en œuvre de la politique RH, gestion administrative et paie, recrutement et intégration, développement des compétences, législation et relations sociales, reporting RH, communication interne. Profil : Bac+4/5 en RH, Droit du travail, Psychologie du travail ou Gestion d''Entreprise, 5 ans d''expérience minimum en généraliste RH idéalement dans un environnement international ou industriel, bilingue Français/Anglais impératif, excellente maîtrise du Code du Travail de Côte d''Ivoire, maîtrise des logiciels de paie et du Pack Office.', '', '', '', 'recrutement.ci@umo-interim.com', true, 'Abidjan', ARRAY['RH', 'Bilingue', 'Paie', 'Recrutement', 'Droit du travail'], false, '', '{"title": "RESPONSABLES RESSOURCES HUMAINES BILINGUE", "company_name": "UMO CI (pour client, distribution de solutions solaires)", "summary": "UMO CI recrute un(e) Responsable RH bilingue (Fran\u00e7ais/Anglais) pour une entreprise de distribution de solutions solaires photovolta\u00efques. Missions : d\u00e9finition et mise en \u0153uvre de la politique RH, gestion administrative et paie, recrutement et int\u00e9gration, d\u00e9veloppement des comp\u00e9tences, l\u00e9gislation et relations sociales, reporting RH, communication interne. Profil : Bac+4/5 en RH, Droit du travail, Psychologie du travail ou Gestion d''Entreprise, 5 ans d''exp\u00e9rience minimum en g\u00e9n\u00e9raliste RH id\u00e9alement dans un environnement international ou industriel, bilingue Fran\u00e7ais/Anglais imp\u00e9ratif, excellente ma\u00eetrise du Code du Travail de C\u00f4te d''Ivoire, ma\u00eetrise des logiciels de paie et du Pack Office.", "contact": null, "lettre_motivation": null, "objet": null, "urls": null, "email": "recrutement.ci@umo-interim.com", "deadline": "30/03/2026", "niveau": "BAC+4", "lieu": "Abidjan", "tags": ["RH", "Bilingue", "Paie", "Recrutement", "Droit du travail"], "salary_range": null}'),
('PERSONNEL DE MAINTENANCE MÉCANIQUE (SOUDEUR, AJUSTEUR ET GRÉEUR)', 'AFREX (pour société de cimenterie)', 'manual_extraction_161', '18/04/2026', 'BAC+2, BAC+1, BAC, BT', 'AFREX recrute pour une société de cimenterie du personnel de maintenance mécanique : Soudeur, Ajusteur, Gréeur. Missions selon métier : soudage, réparation, fabrication de pièces, contrôle qualité (Soudeur) ; installation, assemblage, entretien, alignement, remplacement de composants, diagnostic (Ajusteur) ; levage, déplacement, vérification des équipements, élingage, communication avec grutiers (Gréeur). Profil : formation technique en mécanique industrielle, maintenance ou équivalent, expérience significative en environnement industriel (cimenterie idéalement), bonne maîtrise des équipements mécaniques et outils techniques, rigueur, sécurité, travail en équipe, capacité d''intervention en urgence.', 'Candidature – Soudeur / Ajusteur / Gréeur', '', '', 'recrutement@afrex-group.com', true, 'Yopougon', ARRAY['Maintenance', 'Mécanique', 'Soudure', 'Ajustage', 'Gréeur', 'Industrie'], false, '', '{"title": "PERSONNEL DE MAINTENANCE M\u00c9CANIQUE (SOUDEUR, AJUSTEUR ET GR\u00c9EUR)", "company_name": "AFREX (pour soci\u00e9t\u00e9 de cimenterie)", "summary": "AFREX recrute pour une soci\u00e9t\u00e9 de cimenterie du personnel de maintenance m\u00e9canique : Soudeur, Ajusteur, Gr\u00e9eur. Missions selon m\u00e9tier : soudage, r\u00e9paration, fabrication de pi\u00e8ces, contr\u00f4le qualit\u00e9 (Soudeur) ; installation, assemblage, entretien, alignement, remplacement de composants, diagnostic (Ajusteur) ; levage, d\u00e9placement, v\u00e9rification des \u00e9quipements, \u00e9lingage, communication avec grutiers (Gr\u00e9eur). Profil : formation technique en m\u00e9canique industrielle, maintenance ou \u00e9quivalent, exp\u00e9rience significative en environnement industriel (cimenterie id\u00e9alement), bonne ma\u00eetrise des \u00e9quipements m\u00e9caniques et outils techniques, rigueur, s\u00e9curit\u00e9, travail en \u00e9quipe, capacit\u00e9 d''intervention en urgence.", "contact": null, "lettre_motivation": null, "objet": "Candidature \u2013 Soudeur / Ajusteur / Gr\u00e9eur", "urls": null, "email": "recrutement@afrex-group.com", "deadline": "18/04/2026", "niveau": "BAC+2, BAC+1, BAC, BT", "lieu": "Yopougon", "tags": ["Maintenance", "M\u00e9canique", "Soudure", "Ajustage", "Gr\u00e9eur", "Industrie"], "salary_range": null}'),
