('BOULANGER', '', 'manual_extraction_217', '30/04/2026', 'BEPC, BAC, BT', 'Recrutement d''un(e) boulanger(ère). Missions : préparer les ingrédients, pétrir les pâtes, réaliser les plats, dressage, cuisson, veiller à la qualité, respecter les règles d''hygiène, participer à l''entretien du matériel, gérer les stocks, maintenir la propreté, collaborer avec l''équipe. Profil : CAP/BEP Cuisine ou Formation en boulangerie ou expérience significative, disponible immédiatement, habiter Marcory, Koumassi ou Port Bouet.', '', '', '', 'recrutementecreaf@gmail.com', true, 'MARCORY RESIDENTIEL NON LOIN DE LA PHARMACIE PTT', ARRAY['Boulangerie', 'Pâtisserie', 'Production'], false, '', '{"title": "BOULANGER", "company_name": null, "summary": "Recrutement d''un(e) boulanger(\u00e8re). Missions : pr\u00e9parer les ingr\u00e9dients, p\u00e9trir les p\u00e2tes, r\u00e9aliser les plats, dressage, cuisson, veiller \u00e0 la qualit\u00e9, respecter les r\u00e8gles d''hygi\u00e8ne, participer \u00e0 l''entretien du mat\u00e9riel, g\u00e9rer les stocks, maintenir la propret\u00e9, collaborer avec l''\u00e9quipe. Profil : CAP/BEP Cuisine ou Formation en boulangerie ou exp\u00e9rience significative, disponible imm\u00e9diatement, habiter Marcory, Koumassi ou Port Bouet.", "contact": null, "lettre_motivation": null, "objet": null, "urls": null, "email": "recrutementecreaf@gmail.com", "deadline": "30/04/2026", "niveau": "BEPC, BAC, BT", "lieu": "MARCORY RESIDENTIEL NON LOIN DE LA PHARMACIE PTT", "tags": ["Boulangerie", "P\u00e2tisserie", "Production"], "salary_range": null}'),
('COMPTABLE', '', 'manual_extraction_218', '30/03/2026', 'BAC+5, BAC+4, BAC+3', 'Recrutement d''un(e) Comptable. Missions : suivi et mise en paiement des factures, traitement et enregistrement des opérations de trésorerie, analyse des comptes auxiliaires, établissement des états de rapprochements bancaires, traitement et comptabilisation des écritures de provision, déclarations fiscales, classement et archivage, reporting. Profil : Bac+3 en Comptabilité, Gestion ou Finance, connaissance des normes SYSCOHADA et IFRS, fiscalité, conduite d''audit financier, bonne maîtrise d''un logiciel comptable, capacité d''analyse et de synthèse, rigueur, minutie, organisation, orienté résultat, proactif, capacité à travailler sous pression, parfaite maîtrise de Word et Excel.', '', '', '', 'assistantegd@outlook.fr', true, 'Abidjan Cocody Angré 8e tranche pharmacie 8e tranche', ARRAY['Comptabilité', 'Finance', 'Fiscalité'], true, 'OUI', '{"title": "COMPTABLE", "company_name": null, "summary": "Recrutement d''un(e) Comptable. Missions : suivi et mise en paiement des factures, traitement et enregistrement des op\u00e9rations de tr\u00e9sorerie, analyse des comptes auxiliaires, \u00e9tablissement des \u00e9tats de rapprochements bancaires, traitement et comptabilisation des \u00e9critures de provision, d\u00e9clarations fiscales, classement et archivage, reporting. Profil : Bac+3 en Comptabilit\u00e9, Gestion ou Finance, connaissance des normes SYSCOHADA et IFRS, fiscalit\u00e9, conduite d''audit financier, bonne ma\u00eetrise d''un logiciel comptable, capacit\u00e9 d''analyse et de synth\u00e8se, rigueur, minutie, organisation, orient\u00e9 r\u00e9sultat, proactif, capacit\u00e9 \u00e0 travailler sous pression, parfaite ma\u00eetrise de Word et Excel.", "contact": null, "lettre_motivation": "OUI", "objet": null, "urls": null, "email": "assistantegd@outlook.fr", "deadline": "30/03/2026", "niveau": "BAC+5, BAC+4, BAC+3", "lieu": "Abidjan Cocody Angr\u00e9 8e tranche pharmacie 8e tranch