handising, candidature f\u00e9minine encourag\u00e9e.", "contact": null, "lettre_motivation": null, "objet": "COMMERCIAL(E) GRANDE DISTRIBUTION", "urls": null, "email": "serges.toualou@copaci.co, serges.toualou@copaci.com, recrutrh45@gmail.com", "deadline": "27/03/2026", "niveau": "BAC+2", "lieu": "COPACI ZONE INDUSTRIELLE DE YOPOUGON", "tags": ["Grande distribution", "Vente", "Cosm\u00e9tiques", "Merchandising"], "salary_range": null}'),
