('STAGIAIRE CHARGE(E) DE LA CLIENTELE ET DE LA LOGISTIQUE CULINAIRE- SERVICE TRAITEUR', '', 'manual_extraction_294', '30/03/2026', 'BAC+3, BAC+2', 'Recrutement d''un(e) stagiaire chargé(e) de la clientèle et logistique culinaire. Missions : gestion de la clientèle depuis la communication des menus jusqu''à la gestion des comptes clients pour un Service Traiteur. Activités : prévisions avant commandes, commande alimentaire, gestion des stocks, élaboration de menus, relation avec les fournisseurs, relation directe avec la cuisine, suivi des commandes, suivi des livraisons, prise de commandes téléphoniques, gestion des abonnements, saisie des fiches techniques, élaboration des factures, assistance éventuelle en cuisine. Profil : Bac+2 en hôtellerie, commerce, préférable, 2 ans d''expérience dans la restauration/hôtellerie, maîtrise de Excel, Word et PowerPoint, bonne maîtrise des réseaux sociaux, expérience en tenue de caisse souhaitée, créativité élevée, rigueur, réactivité, sens de l''organisation, autonomie, sens des responsabilités, dynamisme, disponibilité, courtoisie, qualités relationnelles, sens de la communication, persuasion, bon sens de l''organisation, rigueur, bonne capacité d''analyse et d''anticipation, esprit d''équipe.', 'ASSISTANT(E) STAGIAIRE CHARGE(E) DE LA LOGISTIQUE CULINAIRE ET DU SERVICE CLIENT', '', '', 'recrutement@concept360.ci', true, 'II PLATEAUX', ARRAY['Stage', 'Traiteur', 'Logistique', 'Service client'], true, 'OUI', '{"title": "STAGIAIRE CHARGE(E) DE LA CLIENTELE ET DE LA LOGISTIQUE CULINAIRE- SERVICE TRAITEUR", "company_name": null, "summary": "Recrutement d''un(e) stagiaire charg\u00e9(e) de la client\u00e8le et logistique culinaire. Missions : gestion de la client\u00e8le depuis la communication des menus jusqu''\u00e0 la gestion des comptes clients pour un Service Traiteur. Activit\u00e9s : pr\u00e9visions avant commandes, commande alimentaire, gestion des stocks, \u00e9laboration de menus, relation avec les fournisseurs, relation directe avec la cuisine, suivi des commandes, suivi des livraisons, prise de commandes t\u00e9l\u00e9phoniques, gestion des abonnements, saisie des fiches techniques, \u00e9laboration des factures, assistance \u00e9ventuelle en cuisine. Profil : Bac+2 en h\u00f4tellerie, commerce, pr\u00e9f\u00e9rable, 2 ans d''exp\u00e9rience dans la restauration/h\u00f4tellerie, ma\u00eetrise de Excel, Word et PowerPoint, bonne ma\u00eetrise des r\u00e9seaux sociaux, exp\u00e9rience en tenue de caisse souhait\u00e9e, cr\u00e9ativit\u00e9 \u00e9lev\u00e9e, rigueur, r\u00e9activit\u00e9, sens de l''organisation, autonomie, sens des responsabilit\u00e9s, dynamisme, disponibilit\u00e9, courtoisie, qualit\u00e9s relationnelles, sens de la communication, persuasion, bon sens de l''organisation, rigueur, bonne capacit\u00e9 d''analyse et d''anticipation, esprit d''\u00e9quipe.", "contact": null, "lettre_motivation": "OUI", "objet": "ASSISTANT(E) STAGIAIRE CHARGE(E) DE LA LOGISTIQUE CULINAIRE ET DU SERVICE CLIENT", "urls": null, "email": "recrutement@concept360.ci", "deadline": "30/03/2026", "niveau": "BAC+3, BAC+2", "lieu": "II PLATEAUX", "tags": ["Stage", "Traiteur", "Logistique", "Service client"], "salary_range": null}'),
('CONSEILLER CLIENT (H/F) – CENTRE D’APPELS', '', 'manual_extraction_295', '15/04/2026', 'BAC+2', 'Recrutement d''un Conseiller Client en centre d''appels. Missions : accueillir et accompagner les usagers par téléphone et outils digitaux, comprendre les besoins et orienter, organiser et planifier les demandes de prise en charge, assurer un suivi, apporter une assistance sur l''utilisation des services digitaux, contribuer à maintenir un niveau élevé de qualité de service. Profil : excellent sens de l''écoute et du service, savoir rassurer et accompagner avec empathie, organisé, rigoureux, réactif, à l''aise au téléphone et avec les outils informatiques, aime travailler en équipe dans un environnement dynamique.', 'Candidature – Conseiller Client', '', '', 'recrutement@pcplusgroupholding.com', true, 'Côte d''Ivoire', ARRAY['Centre d''appels', 'Service client', 'Conseiller'], true, 'OUI', '{"title": "CONSEILLER CLIENT (H/F) \u2013 CENTRE D\u2019APPELS", "company_name": null, "summary": "Recrutement d''un Conseiller Client en centre d''appels. Missions : accueillir et accompagner les usagers par t\u00e9l\u00e9phone et outils digitaux, comprendre les besoins et orienter, organiser et planifier les demandes de prise en charge, assurer un suivi, apporter une assistance sur l''utilisation des services digitaux, contribuer \u00e0 maintenir un niveau \u00e9lev\u00e9 de qualit\u00e9 de service. Profil : excellent sens de l''\u00e9coute et du service, savoir rassurer et accompagner avec empathie, organis\u00e9, rigoureux, r\u00e9actif, \u00e0 l''aise au t\u00e9l\u00e9phone et avec les outils informatiques, aime travailler en \u00e9quipe dans un environnement dynamique.", "contact": null, "lettre_motivation": "OUI", "objet": "Candidature \u2013 Conseiller Client", "urls": null, "email": "recrutement@pcplusgroupholding.com", "deadline": "15/04/2026", "niveau": "BAC+2", "lieu": "C\u00f4te d''Ivoire", "tags": ["Centre d''appels", "Service client", "Conseiller"], "salary_range": nu