('1 STAGIAIRES COMPTABLES', '', 'manual_extraction_299', '23/03/2026', 'BAC+2', 'Un cabinet d''assistance de gestion recrute 1 stagiaire comptable admissible BTS. Missions : enregistrer les factures, faire les déclarations, analyser et ranger les pièces comptables, faire des imputations. Profil : âgé de 20 à 30 ans, bonne présentation physique et vestimentaire, bonne expression écrite et orale, niveau minimum BAC+2, admissibilité BTS.', 'COMPTABLE STAGIARE (préciser dans l''objet)', '', '', 'recrutong24@gmail.com', true, 'Poste basé dans la commune de Cocody', ARRAY['Stage', 'Comptabilité'], true, 'OUI', '{"title": "1 STAGIAIRES COMPTABLES", "company_name": null, "summary": "Un cabinet d''assistance de gestion recrute 1 stagiaire comptable admissible BTS. Missions : enregistrer les factures, faire les d\u00e9clarations, analyser et ranger les pi\u00e8ces comptables, faire des imputations. Profil : \u00e2g\u00e9 de 20 \u00e0 30 ans, bonne pr\u00e9sentation physique et vestimentaire, bonne expression \u00e9crite et orale, niveau minimum BAC+2, admissibilit\u00e9 BTS.", "contact": null, "lettre_motivation": "OUI", "objet": "COMPTABLE STAGIARE (pr\u00e9ciser dans l''objet)", "urls": null, "email": "recrutong24@gmail.com", "deadline": "23/03/2026", "niveau": "BAC+2", "lieu": "Poste bas\u00e9 dans la commune de Cocody", "tags": ["Stage", "Comptabilit\u00e9"], "salary_range": null}'),
('CHEF CUISINIER', '', 'manual_extraction_300', '25/03/2026', 'CAP, BT', 'Un restaurant abidjanais recherche un(e) Chef cuisinier. Activités principales : élaborer des fiches techniques, confectionner les plats de la carte, maintenir la qualité, adapter la production, organiser le travail en cuisine, gérer les stocks, contrôler l''utilisation des articles, s''assurer de l''entretien et de la propreté. Profil : H/F, diplômé d''un Bac Pro Cuisine ou équivalent avec au moins 2 ans d''expérience similaire, bonne connaissance des techniques de cuisine, normes d''hygiène et sécurité alimentaire, spécialité en cuisine africaine et hors d''œuvre. Atouts : capacité managériale, organisation, relationnelle, proactivité, créativité, esprit d''équipe, disponibilité, sens de la propreté.', '', '', '', 'talents@objectifrh.net', true, 'Abidjan', ARRAY['Cuisine', 'Restauration', 'Chef'], true, 'OUI', '{"title": "CHEF CUISINIER", "company_name": null, "summary": "Un restaurant abidjanais recherche un(e) Chef cuisinier. Activit\u00e9s principales : \u00e9laborer des fiches techniques, confectionner les plats de la carte, maintenir la qualit\u00e9, adapter la production, organiser le travail en cuisine, g\u00e9rer les stocks, contr\u00f4ler l''utilisation des articles, s''assurer de l''entretien et de la propret\u00e9. Profil : H/F, dipl\u00f4m\u00e9 d''un Bac Pro Cuisine ou \u00e9quivalent avec au moins 2 ans d''exp\u00e9rience similaire, bonne connaissance des techniques de cuisine, normes d''hygi\u00e8ne et s\u00e9curit\u00e9 alimentaire, sp\u00e9cialit\u00e9 en cuisine africaine et hors d''\u0153uvre. Atouts : capacit\u00e9 manag\u00e9riale, organisation, relationnelle, proactivit\u00e9, cr\u00e9ativit\u00e9, esprit d''\u00e9quipe, disponibilit\u00e9, sens de la propret\u00e9.", "contact": null, "lettre_motivation": "OUI", "objet": null, "urls": null, "email": "talents@objectifrh.net", "deadline": "25/03/2026", "niveau": "CAP, BT", "lieu": "Abidjan", "tags": ["Cuisine", "Restauration", "Chef"], "salary_range": null}'),
('ASSISTANT QUALITE SECURITE ENVIRONNEMENT', '', 'manual_extraction_301', '23/03/2026', 'BAC+4', 'Poste d''Assistant Qualité Sécurité Environnement.', '', '', '', '', true, 'ABIDJAN', ARRAY['QSE', 'Qualité', 'Sécurité', 'Environnement'], false, '', '{"title": "ASSISTANT QUALITE SECURITE ENVIRONNEMENT", "company_name": null, "summary": "Poste d''Assistant Qualit\u00e9 S\u00e9curit\u00e9 Environnement.", "contact": null, "lettre_motivation": null, "objet": null, "urls": null, "email": null, "deadline": "23/03/2026", "niveau": "BAC+4", "lieu": "ABIDJAN", "tags": ["QSE", "Qualit\u00e9", "S\u00e9curit\u00e9", "Environnement"], "salary_range": null}'),
('STAGIAIRE CONSULTANT RH', 'Objectif RH', 'manual_extraction_302', '27/03/2026', 'BAC+3', 'Le cabinet Objectif RH recrute un Stagiaire Consultant RH. Activités principales : assister les consultants dans la réalisation de missions de conseil, d''assistance et de formation, analyser des pratiques de GRH et faire des recommandations, concevoir des outils RH, suivre des études RH, assister à la préparation de module de formation, accompagner des prospections commerciales. Profil : H/F diplômé(e) d''un Bac+3 à Bac+5 en GRH, Management ou équivalent, connaissances de base des processus RH et de la législation, bonne maîtrise des outils informatiques (Word, Excel, PowerPoint), une première expérience en stage ou projet en entreprise ou cabinet serait un plus. Atouts : motivation, proactivité, capacité d''écoute et de compréhension des besoins, orienté résultats, créativité, capacité relationnelle, intérêt pour l''apprentissage.', '', '', '', 'talents@objectifrh.net', true, 'Cocody, les deux plateaux vallons', ARRAY['Stage', 'Consultant RH', 'GRH'], true, 'OUI', '{"title": "STAGIAIRE CONSULTANT RH", "company_name": "Objectif RH", "summary": "Le cabinet Objectif RH recrute un Stagiaire Consultant RH. Activit\u00e9s principales : assister les consultants dans la r\u00e9alisation de missions de conseil, d''assistance et de formation, analyser des pratiques de GRH et faire des recommandations, concevoir des outils RH, suivre des \u00e9tudes RH, assister \u00e0 la pr\u00e9paration de module de formation, accompagner des prospections commerciales. Profil : H/F dipl\u00f4m\u00e9(e) d''un Bac+3 \u00e0 Bac+5 en GRH, Management ou \u00e9quivalent, connaissances de base des processus RH et de la l\u00e9gislation, bonne ma\u00eetrise des outils informatiques (Word, Excel, PowerPoint), une premi\u00e8re exp\u00e9rience en stage ou projet en entreprise ou cabinet serait un plus. Atouts : motivation, proactivit\u00e9, capacit\u00e9 d''\u00e9coute et de compr\u00e9hension des besoins, orient\u00e9 r\u00e9sultats, cr\u00e9ativit\u00e9, capacit\u00e9 relationnelle, int\u00e9r\u00eat pour l''apprentissage.", "contact": null, "lettre_motivation": "OUI", "objet": null, "urls": null, "email": "talents@objectifrh.net", "deadline": "27/03/2026", "niveau": "BAC+3", "lieu": "Cocody, les deux plateaux vallons", "tags": ["Stage", "Consultant RH", "GRH"], "salary_range": null}'),
('COMMERCIAL', '', 'manual_extraction_303', '31/03/2026', 'BAC+2', 'Une société agro-alimentaire recrute un Commercial. Missions : assurer le référencement des produits, développement du portefeuille client et du chiffre d''affaires dans sa zone de couverture (grossistes et démi-grossistes), prospecter, développer et maintenir le bon relationnel, maîtriser les stocks, suivre les échéances et recouvrement, merchandising, fidéliser, reporting, inventaires. Profil : Bac+2 en Commerce ou équivalent, 2 ans d''expérience avérée, maîtrise des techniques de vente et négociation, management du client, bonne connaissance du secteur d''activité, flexibilité, sens du relationnel, force de persuasion, autonomie, esprit d''équipe, dynamisme, réactivité. Type de contrat: CDD, salaire 150.000F.', 'intitulé du poste', '', '', 'recrutement@siprochim.com', true, 'ABIDJAN / YOPOUGON ZONE INDUSTRIELLE', ARRAY['Commerce', 'Vente', 'Agroalimentaire'], false, '', '{"title": "COMMERCIAL", "company_name": null, "summary": "Une soci\u00e9t\u00e9 agro-alimentaire recrute un Commercial. Missions : assurer le r\u00e9f\u00e9rencement des produits, d\u00e9veloppement du portefeuille client et du chiffre d''affaires dans sa zone de couverture (grossistes et d\u00e9mi-grossistes), prospecter, d\u00e9velopper et maintenir le bon relationnel, ma\u00eetriser les stocks, suivre les \u00e9ch\u00e9ances et recouvrement, merchandising, fid\u00e9liser, reporting, inventaires. Profil : Bac+2 en Commerce ou \u00e9quivalent, 2 ans d''exp\u00e9rience av\u00e9r\u00e9e, ma\u00eetrise des techniques de vente et n\u00e9gociation, management du client, bonne connaissance du secteur d''activit\u00e9, flexibilit\u00e9, sens du relationnel, force de persuasion, autonomie, esprit d''\u00e9quipe, dynamisme, r\u00e9activit\u00e9. Type de contrat: CDD, salaire 150.000F.", "contact": null, "lettre_motivation": null, "objet": "intitul\u00e9 du poste", "urls": null, "email": "recrutement@siprochim.com", "deadline": "31/03/202