ci@gmail.com", "deadline": "23/03/2026", "niveau": "BAC+3, BAC+2", "lieu": "ABIDJAN", "tags": ["Community management", "R\u00e9seaux sociaux", "Marketing digital", "Cr\u00e9ation de contenu"], "salary_range": null}'),
