('PROMOTEUR DIGITAL', 'Centre d’Incubation Commercial (CIC)', 'manual_extraction_406', '23/03/2026', 'BAC+4, BAC+3, BAC+2', 'Centre d''Incubation Commercial recrute des agents digitaux pour promouvoir des produits naturels de bien-être. Missions : promouvoir des produits naturels de bien-être et de santé, utiliser les réseaux sociaux, WhatsApp, internet et son réseau personnel, identifier et accompagner les clients, générer des ventes. Le CIC se charge de la gestion des commandes, livraison, service client, paiement des commissions. Rémunération : commissions très attractives, bonus de performance possibles. Profil : motivé, dynamique, à l''aise avec WhatsApp et les réseaux sociaux, intéressé par le bien-être et la santé naturelle, esprit entrepreneurial, capacité à travailler de manière autonome. Aucune expérience obligatoire.', 'PROMOTEUR DIGITAL SANTÉ', '', '', 'recrut.cic.2026kf@gmail.com', true, 'Côte d''Ivoire', ARRAY['Promotion', 'Digital', 'Santé naturelle', 'Vente en ligne'], false, '', '{"title": "PROMOTEUR DIGITAL", "company_name": "Centre d\u2019Incubation Commercial (CIC)", "summary": "Centre d''Incubation Commercial recrute des agents digitaux pour promouvoir des produits naturels de bien-\u00eatre. Missions : promouvoir des produits naturels de bien-\u00eatre et de sant\u00e9, utiliser les r\u00e9seaux sociaux, WhatsApp, internet et son r\u00e9seau personnel, identifier et accompagner les clients, g\u00e9n\u00e9rer des ventes. Le CIC se charge de la gestion des commandes, livraison, service client, paiement des commissions. R\u00e9mun\u00e9ration : commissions tr\u00e8s attractives, bonus de performance possibles. Profil : motiv\u00e9, dynamique, \u00e0 l''aise avec WhatsApp et les r\u00e9seaux sociaux, int\u00e9ress\u00e9 par le bien-\u00eatre et la sant\u00e9 naturelle, esprit entrepreneurial, capacit\u00e9 \u00e0 travailler de mani\u00e8re autonome. Aucune exp\u00e9rience obligatoire.", "contact": null, "lettre_motivation": null, "objet": "PROMOTEUR DIGITAL SANT\u00c9", "urls": null, "email": "recrut.cic.2026kf@gmail.com", "deadline": "23/03/2026", "niveau": "BAC+4, BAC+3, BAC+2", "lieu": "C\u00f4te d''Ivoire", "tags": ["Promotion", "Digital", "Sant\u00e9 naturelle", "Vente en ligne"], "salary_range": "commissions tr\u00e8s attractives"}'),
('COMMERCIAL(E) SHOWROOM', '', 'manual_extraction_407', '22/03/2026', 'BAC+3, BAC+2', 'Recrutement d''un(e) Commercial(e) Showroom. Missions : accueil et conseil client, vente et négociation, gestion du showroom, suivi commercial et fidélisation, appui au département marketing, prospection commerciale digitale, veille concurrentielle et marché, reporting. Profil : Bac+2/Bac+3 (BTS Gestion commerciale, marketing, commerce), 2 ans d''expérience similaire, maîtrise des techniques commerciales et de vente, bonne maîtrise du français (oral et écrit), bonne présentation, connaissance du Pack Office, bonne maîtrise des réseaux sociaux et des outils numériques, capacités de prospection.', 'COMMERCIAL(E) SHOWROOM', '', '', 'recruitment@nourivoire.com', true, 'Abidjan', ARRAY['Commerce', 'Showroom', 'Vente', 'Marketing digital'], false, '', '{"title": "COMMERCIAL(E) SHOWROOM", "company_name": null, "summary": "Recrutement d''un(e) Commercial(e) Showroom. Missions : accueil et conseil client, vente et n\u00e9gociation, gestion du showroom, suivi commercial et fid\u00e9lisation, appui au d\u00e9partement marketing, prospection commerciale digitale, veille concurrentielle et march\u00e9, reporting. Profil : Bac+2/Bac+3 (BTS Gestion commerciale, marketing, commerce), 2 ans d''exp\u00e9rience similaire, ma\u00eetrise des techniques commerciales et de vente, bonne ma\u00eetrise du fran\u00e7ais (oral et \u00e9crit), bonne pr\u00e9sentation, connaissance du Pack Office, bonne ma\u00eetrise des r\u00e9seaux sociaux et des outils num\u00e9riques, capacit\u00e9s de prospection.", "contact": null, "lettre_motivation": null, "objet": "COMMERCIAL(E) SHOWROOM", "urls": null, "email": "recruitment@nourivoire.com", "deadline": "22/03/2026", "niveau": "BAC+3, BAC+2", "lieu": "Abidjan", "tags": ["Commerce", "Showroom", "Vente", "Marketing digital"], "salary_range": null}'),
('ASSISTANT ENTREPÔT/ASSISTANTE ENTREPÔT BILINGUE', '', 'manual_extraction_408', '23/03/2026', 'BAC+2', 'Recrutement de 5 assistant(e)s d''entrepôt bilingues. Responsabilités : coordination des opérations (réception, vérification, expédition, rangement, préparation des commandes, chargement/déchargement, inventaires), support administratif (tenue des bases de données, documentation), optimisation des processus, soutien à l''équipe. Profil : parler couramment l''anglais (oral et écrit), Bac+2 ou plus en Logistique ou transport, 2 ans d''expérience dans le secteur de la logistique, distribution ou industrie, capacité à travailler efficacement dans un environnement dynamique, connaissance des principes de base de la logistique et de la gestion des stocks, compétences organisationnelles, souci du détail, maîtrise des outils informatiques (systèmes de gestion des stocks et logiciels de bureautique), bonne pratique des règles de sécurité en entrepôt.', 'ASSISTANT(E) ENTREPOT', '', '', 'moussa@sunda.com', true, 'Zone industrielle de BONOUA, Côte d’Ivoire', ARRAY['Entrepôt', 'Logistique', 'Bilingue', 'Gestion de stock'], false, '', '{"title": "ASSISTANT ENTREP\u00d4T/ASSISTANTE ENTREP\u00d4T BILINGUE", "company_name": null, "summary": "Recrutement de 5 assistant(e)s d''entrep\u00f4t bilingues. Responsabilit\u00e9s : coordination des op\u00e9rations (r\u00e9ception, v\u00e9rification, exp\u00e9dition, rangement, pr\u00e9paration des commandes, chargement/d\u00e9chargement, inventaires), support administratif (tenue des bases de donn\u00e9es, documentation), optimisation des processus, soutien \u00e0 l''\u00e9quipe. Profil : parler couramment l''anglais (oral et \u00e9crit), Bac+2 ou plus en Logistique ou transport, 2 ans d''exp\u00e9rience dans le secteur de la logistique, distribution ou industrie, capacit\u00e9 \u00e0 travailler efficacement dans un environnement dynamique, connaissance des principes de base de la logistique et de la gestion des stocks, comp\u00e9tences organisationnelles, souci du d\u00e9tail, ma\u00eetrise des outils informatiques (syst\u00e8mes de gestion des stocks et logiciels de bureautique), bonne pratique des r\u00e8gles de s\u00e9curit\u00e9 en entrep\u00f4t.", "contact": null, "lettre_motivation": null, "objet": "ASSISTANT(E) ENTREPOT", "urls": null, "email": "moussa@sunda.com", "deadline": "23/03/2026", "niveau": "BAC+2", "lieu": "Zone industrielle de BONOUA, C\u00f4te d\u2019Ivoire", "tags": ["Entrep\u00f4t", "Logistique", "Bilingue", "Gestion de stock"], "salary_range": null}'),
