('AGENT QUALITE', '', 'manual_extraction_412', '23/03/2026', 'BAC+2', 'Recrutement d''un Agent Qualité pour le projet IEEA. Missions : vérifier la complétude et la cohérence des données collectées, contrôler la conformité des pièces justificatives, identifier et signaler les anomalies, contribuer à la correction des erreurs, produire des rapports de contrôle qualité. Profil : BAC/BAC+2 minimum, expérience en collecte ou contrôle de données souhaitée, rigueur, sens du détail, maîtrise des outils numériques, capacité à gérer un volume de dossiers quotidien tout en respectant les délais.', 'AGENT QUALITES', '', '', 'recrutement@sns.ci', true, 'ABIDJAN', ARRAY['Qualité', 'Contrôle', 'Collecte de données'], false, '', '{"title": "AGENT QUALITE", "company_name": null, "summary": "Recrutement d''un Agent Qualit\u00e9 pour le projet IEEA. Missions : v\u00e9rifier la compl\u00e9tude et la coh\u00e9rence des donn\u00e9es collect\u00e9es, contr\u00f4ler la conformit\u00e9 des pi\u00e8ces justificatives, identifier et signaler les anomalies, contribuer \u00e0 la correction des erreurs, produire des rapports de contr\u00f4le qualit\u00e9. Profil : BAC/BAC+2 minimum, exp\u00e9rience en collecte ou contr\u00f4le de donn\u00e9es souhait\u00e9e, rigueur, sens du d\u00e9tail, ma\u00eetrise des outils num\u00e9riques, capacit\u00e9 \u00e0 g\u00e9rer un volume de dossiers quotidien tout en respectant les d\u00e9lais.", "contact": null, "lettre_motivation": null, "objet": "AGENT QUALITES", "urls": null, "email": "recrutement@sns.ci", "deadline": "23/03/2026", "niveau": "BAC+2", "lieu": "ABIDJAN", "tags": ["Qualit\u00e9", "Contr\u00f4le", "Collecte de donn\u00e9es"], "salary_range": null}'),
